/** miraeAssetMapper.regMspMiraeAssetIf */
INSERT INTO MSP_MIRAE_ASSET_IF
    (
         IF_YM
         , TRADE_CD
         , MA_KEY
         , CUST_NM
         , CI
         , INSR_FEE
         , INSR_JOIN_DT
         , INSR_TMNT_DT
         , INSR_NM
         , INSR_CD
         , KTM_CUST_YN
         , KTM_OPEN_DT
         , KTM_CNTR_NO
         , KTM_AD_FEE
         , REGST_DTTM
    ) VALUES (
        #{ifYm}
        , #{tradeCd}
        , #{maKey}
        , #{custNm}
        , #{ci}
        , #{insrFee}
        , #{insrJoinDt}
        , #{insrTmntDt}
        , #{insrNm}
        , #{insrCd}
        , #{ktmCustYn}
        , #{ktmOpenDt}
        , #{ktmCntrNo}
        , #{ktmAdFee}
        , SYSDATE
    )

mapper.delete:
/* miraeAssetMapper.delMspMiraeAssetIf */
DELETE FROM MSP_MIRAE_ASSET_IF
WHERE  IF_YM = #{ifYm}
AND    TRADE_CD = #{tradeCd}
